import os
import zipfile
import tarfile

def create_archive(source_paths, archive_name, archive_format='zip'):
    """
    Creates an archive (zip or tar) from a list of source files/directories.

    Args:
        source_paths (list): A list of file or directory paths to be added to the archive.
        archive_name (str): The name of the archive file to create (e.g., 'my_archive.zip', 'my_archive.tar.gz').
        archive_format (str): The format of the archive ('zip', 'tar', 'tar.gz', 'tar.bz2', 'tar.xz').
                              Defaults to 'zip'.
    """
    if archive_format == 'zip':
        with zipfile.ZipFile(archive_name, 'w', zipfile.Zip_DEFLATED) as zipf:
            for source_path in source_paths:
                if not os.path.exists(source_path):
                    continue

                if os.path.isfile(source_path):
                    zipf.write(source_path, os.path.basename(source_path))
                elif os.path.isdir(source_path):
                    base_dir_name = os.path.basename(source_path)
                    for root, _, files in os.walk(source_path):
                        # Add current directory itself to preserve empty directories
                        relative_path_to_root = os.path.relpath(root, source_path)
                        archive_dir_name = os.path.join(base_dir_name, relative_path_to_root)
                        if archive_dir_name: # Don't add an empty string as a directory
                            zipf.write(root, archive_dir_name)

                        for file in files:
                            file_path = os.path.join(root, file)
                            archive_file_name = os.path.join(base_dir_name, os.path.relpath(file_path, source_path))
                            zipf.write(file_path, archive_file_name)
    elif archive_format.startswith('tar'):
        mode = 'w'
        if archive_format == 'tar.gz':
            mode = 'w:gz'
        elif archive_format == 'tar.bz2':
            mode = 'w:bz2'
        elif archive_format == 'tar.xz':
            mode = 'w:xz'
        elif archive_format != 'tar':
            raise ValueError(f"Unsupported tar archive format: {archive_format}")

        with tarfile.open(archive_name, mode) as tarf:
            for source_path in source_paths:
                if not os.path.exists(source_path):
                    continue
                tarf.add(source_path, arcname=os.path.basename(source_path))
    else:
        raise ValueError(f"Unsupported archive format: {archive_format}")
